        public string GetState(string _zip_code)
        {
            string state = string.Empty;

            if (zip_codes.TryGetValue(_zip_code, out County value))
            {
                state = value.StateName;
            }
            return state;
        }
        public string GetCounty(string _zip_code)
        {
            string county = string.Empty;

            if (zip_codes.TryGetValue(_zip_code, out County value))
            {
                county = value.CountyName;
            }
            return county;
        }

        public bool GetTax(string _zip_code)
        {
            bool decision = false;

            if (zip_codes.TryGetValue(_zip_code, out County value))
            {
                decision = value.Decision == "Tax";
            }
            return decision;
        }
    }
